    "lyricsHtml": "\n<span class=\"chord\" data-chord=\"C\">C</span>                 <span class=\"chord\" data-chord=\"Bb\">Bb</span>              <span class=\"chord\" data-chord=\"F\">F</span>   <span class=\"chord\" data-chord=\"C\">C</span>              \n<span class=\"lyric-line\">Começou a circular o Expres----so 2222</span>\n                   <span class=\"chord\" data-chord=\"Em7\">Em7</span>         <span class=\"chord\" data-chord=\"Dm7\">Dm7</span>   <span class=\"chord\" data-chord=\"G7\">G7</span>    <span class=\"chord\" data-chord=\"C\">C</span>\n<span class=\"lyric-line\">Que parte direto de Bonsucesso pra depois</span>\n                  <span class=\"chord\" data-chord=\"Bb\">Bb</span>              <span class=\"chord\" data-chord=\"F\">F</span>     <span class=\"chord\" data-chord=\"C\">C</span>        \n<span class=\"lyric-line\">Começou a circular o Expres----so 2222</span>\n<span class=\"lyric-line\">Da Central do Brasil</span>\n                 <span class=\"chord\" data-chord=\"Bb\">Bb</span>\n<span class=\"lyric-line\">Que parte direto de Bonsucesso</span>\n<span class=\"chord\" data-chord=\"F\">F</span>                <span class=\"chord\" data-chord=\"C\">C</span>\n<span class=\"lyric-line\">Pra depois do a----no 2000</span>\n                         <span class=\"chord\" data-chord=\"G7\">G7</span>\n<span class=\"lyric-line\">Dizem que tem muita gen-----te de ago----ra</span>\n             <span class=\"chord\" data-chord=\"C\">C</span>\n<span class=\"lyric-line\">Se adiantan----do, partindo pra lá</span>\n        <span class=\"chord\" data-chord=\"G7\">G7</span>\n<span class=\"lyric-line\">Pra 2001 e 2 e tem---po afo---ra</span>\n   <span class=\"chord\" data-chord=\"C\">C</span>                                    <span class=\"chord\" data-chord=\"G/F\">G/F</span>\n<span class=\"lyric-line\">Até onde es---sa estra---da do tempo vai dar</span>\n            <span class=\"chord\" data-chord=\"Em7\">Em7</span>    <span class=\"chord\" data-chord=\"Am7\">Am7</span>\n<span class=\"lyric-line\">Do tempo vai dar</span>\n            <span class=\"chord\" data-chord=\"Dm7\">Dm7</span> <span class=\"chord\" data-chord=\"G7\">G7</span>  <span class=\"chord\" data-chord=\"Dm7\">Dm7</span>      <span class=\"chord\" data-chord=\"G7\">G7</span>        <span class=\"chord\" data-chord=\"C\">C</span>\n<span class=\"lyric-line\">Do tempo vai dar, menina, do tempo vai</span>\n                     <span class=\"chord\" data-chord=\"G7\">G7</span>\n<span class=\"lyric-line\">Segundo quem já andou no Expres---so</span>\n                <span class=\"chord\" data-chord=\"C\">C</span>\n<span class=\"lyric-line\">Lá pelo ano 2000 fica a tal</span>\n                     <span class=\"chord\" data-chord=\"G7\">G7</span>\n<span class=\"lyric-line\">Estação final do per---curso-vida</span>\n                     <span class=\"chord\" data-chord=\"C\">C</span>\n<span class=\"lyric-line\">Na terra-mãe concebi---da</span>\n                                 <span class=\"chord\" data-chord=\"G/F\">G/F</span>\n<span class=\"lyric-line\">De vento, de fogo, de água e sal</span>\n               <span class=\"chord\" data-chord=\"Em7\">Em7</span>  <span class=\"chord\" data-chord=\"Am7\">Am7</span>\n<span class=\"lyric-line\">De água e sal</span>\n               <span class=\"chord\" data-chord=\"Dm7\">Dm7</span>  <span class=\"chord\" data-chord=\"G7\">G7</span>\n<span class=\"lyric-line\">De água e sal</span>\n     <span class=\"chord\" data-chord=\"Dm7\">Dm7</span>      <span class=\"chord\" data-chord=\"G7\">G7</span>     <span class=\"chord\" data-chord=\"C\">C</span>\n<span class=\"lyric-line\">Ô, menina, de água e sal</span>\n                       <span class=\"chord\" data-chord=\"G7\">G7</span>         \n<span class=\"lyric-line\">Dizem que parece o bon---de do mor---ro</span>\n           <span class=\"chord\" data-chord=\"C\">C</span>            \n<span class=\"lyric-line\">Do Corcova---do da---qui</span>\n                <span class=\"chord\" data-chord=\"G7\">G7</span>                \n<span class=\"lyric-line\">Só que não se pe---ga e en---tra e sen---ta e an---da</span>\n      <span class=\"chord\" data-chord=\"C\">C</span>                                              <span class=\"chord\" data-chord=\"G/F\">G/F</span>\n<span class=\"lyric-line\">O tri----lho é fei---to um bri---lho que não tem fim</span>\n                    <span class=\"chord\" data-chord=\"Em7\">Em7</span>   <span class=\"chord\" data-chord=\"Am7\">Am7</span>\n<span class=\"lyric-line\">Oi, que não tem fim</span>\n                <span class=\"chord\" data-chord=\"Dm7\">Dm7</span>  <span class=\"chord\" data-chord=\"G7\">G7</span>\n<span class=\"lyric-line\">Que não tem fim</span>\n     <span class=\"chord\" data-chord=\"Dm7\">Dm7</span>       <span class=\"chord\" data-chord=\"G7\">G7</span>      <span class=\"chord\" data-chord=\"C\">C</span>    \n<span class=\"lyric-line\">Ô, menina, que não tem fim</span>\n                       <span class=\"chord\" data-chord=\"G7\">G7</span>                \n<span class=\"lyric-line\">Nunca se chega no Cris---to concre---to</span>\n                           <span class=\"chord\" data-chord=\"C\">C</span>\n<span class=\"lyric-line\">De matéria ou qualquer coi---sa real</span>\n              <span class=\"chord\" data-chord=\"G7\">G7</span>        \n<span class=\"lyric-line\">Depois de 2001 e 2 e tem---po afo---ra</span>\n       <span class=\"chord\" data-chord=\"C\">C</span>                                         <span class=\"chord\" data-chord=\"G/F\">G/F</span>  \n<span class=\"lyric-line\">O Cris---to é como quem foi visto subindo ao céu</span>\n               <span class=\"chord\" data-chord=\"Em7\">Em7</span>  <span class=\"chord\" data-chord=\"Am7\">Am7</span>\n<span class=\"lyric-line\">Subindo ao céu</span>\n             <span class=\"chord\" data-chord=\"Dm7\">Dm7</span> <span class=\"chord\" data-chord=\"G7\">G7</span>      <span class=\"chord\" data-chord=\"C\">C</span>           \n<span class=\"lyric-line\">Num véu de nu-----vem brilhante subindo ao céu</span>\n",
